<template lang="pug">
  .chats
    .ui.left.aligned.segment.container
      div.fluid
        sui-header(size="large") {{ msg }}
        router-link(to="/")
          img.logo(src="../assets/logo.png")
      .ui.comments
        h3.ui.dividing.header ж≠°ињОзХЩи®А
        .comment(v-for="(c, idx, order) in chats" :key="c.time")
          a.avatar
            i.user.icon
          .content(:class = "bgColors[order % 4]")
            a.author(:href="'mailto:' + c.email", target="_blank")   {{ c.n }} и™™пЉЪ
            vue-simple-markdown.text(:source="c.t")
              .metadata
                span.date -{{ parseTime(c.time) }}
      .ui.form.light-blue
        .two.fields
          .required.field
            label жВ®зЪДе§ІеРН:
            input(type='text' v-model="myName")
          .required.field
            label Email:
            input(type='email' v-model="myEmail")
          .required.field
            label иЂЛзХЩи®А:
            input(type='text' v-model="myText" placeholder="жВ®жГ≥и™™дїАйЇЉпЉЯ")
        .ui.submit.huge.green.button(@click="submit(myName, myEmail, myText)") зХЩи®А
      br
      br

</template>
<script>

export default {
  name: 'Chat',
  props: ['likes', 'chats'],
  data () {
    return {
      msg: 'зХЩи®АзЙИ',
      'myName': 'и®™еЃҐ',
      'myEmail': '',
      'myText': '',
      bgColors: ['light-blue', 'light-green', 'light-yellow', 'light-red']
    }
  },
  methods: {
    submit: function (n, email, t) {
      function validateEmail (email) {
        // eslint-disable-next-line
        var re = /^(([^<>()\[\]\\.,;:\s@"]+(\.[^<>()\[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/
        return re.test(String(email).toLowerCase())
      }
      if (!validateEmail(email)) {
        window.alert('иЂЛиЉЄеЕ•E-mail')
        return
      }
      this.myName = 'и®™еЃҐ'
      this.myEmail = ''
      this.myText = ''
      this.$emit('submit', n, email, t)
    },
    parseTime: function (t) {
      return (new Date(t)).toLocaleDateString()
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>

.fluid {
  text-align: center;
  width:100%;
}
</style>



